(function() {
    var triggerType = "scroll"; 

    if (triggerType === 'scroll' && typeof ScrollTrigger !== 'undefined') {
        gsap.registerPlugin(ScrollTrigger);
    }

    var wrapper = document.getElementById("trg_wrapper-uc_jptv_texto_rodante_gsap_elementor_5316a19");
    if (!wrapper) return;

    var textMask = wrapper.querySelector('.trg-text-mask');
    var anchor = wrapper.querySelector('.trg-anchor'); 
    var lineEl = wrapper.querySelector('.trg-line');

    var duration = parseFloat("0.5") || 0.5;
    // NUEVO: Capturamos el Stagger (Si el usuario lo deja vacío o 0, es bloque sólido)
    var staggerVal = parseFloat("0.05") || 0;

    // --- FUNCIÓN SPLIT TEXT ---
    function splitText(el) {
        var text = el.innerText.trim(); 
        el.innerHTML = ''; 

        text.split('').forEach(function(char) {
            var charContent = char === ' ' ? '&nbsp;' : char;
            var spanWrapper = document.createElement('span');
            spanWrapper.classList.add('trg-char-wrapper');
            var original = document.createElement('span');
            original.classList.add('trg-char');
            original.innerHTML = charContent;
            var clone = document.createElement('span');
            clone.classList.add('trg-char', 'clone');
            clone.innerHTML = charContent;
            spanWrapper.appendChild(original);
            spanWrapper.appendChild(clone);
            el.appendChild(spanWrapper);
        });
    }

    if (textMask && anchor) {
        splitText(textMask);
        var originalChars = textMask.querySelectorAll('.trg-char:not(.clone)');
        var cloneChars = textMask.querySelectorAll('.trg-char.clone');

        // Configuración inicial
        gsap.set(cloneChars, { yPercent: 120 });

        // --- TIMELINE TEXTO ---
        var tlConfig = { paused: true }; 
        if (triggerType === 'scroll') {
            tlConfig.scrollTrigger = {
                trigger: anchor,
                start: "top center",
                end: "bottom top",
                toggleActions: "play none none reverse"
            };
            tlConfig.paused = false; 
        }

        var tl = gsap.timeline(tlConfig);

        // Animación usando la variable 'staggerVal'
        tl.to(originalChars, {
            yPercent: -120, 
            duration: duration,
            ease: "power3.out",
            stagger: staggerVal 
        }, 0);

        tl.to(cloneChars, {
            yPercent: 0,
            duration: duration,
            ease: "power3.out",
            stagger: staggerVal 
        }, 0);

        // --- EVENTOS HOVER ---
        if (triggerType === 'hover') {

            anchor.addEventListener('mouseenter', function() {
                tl.play();

                // Entrada Línea: Crece desde Izquierda
                if(lineEl) {
                    gsap.fromTo(lineEl, 
                        { transformOrigin: "left center", scaleX: 0 }, 
                        { scaleX: 1, duration: 0.4, ease: "power2.out", overwrite: true }
                    );
                }
            });

            anchor.addEventListener('mouseleave', function() {
                tl.reverse();

                // Salida Línea: Se va hacia la Derecha
                if(lineEl) {
                    gsap.to(lineEl, { 
                        transformOrigin: "right center", 
                        scaleX: 0, 
                        duration: 0.6, // Un poco más lento para que se aprecie la salida
                        ease: "power2.inOut", 
                        overwrite: true 
                    });
                }
            });
        }
    }
})();

